import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input from a form
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by encoding it before printing to the web page
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<body>");
        out.println("User input: " + StringEscapeUtils.escapeHtml4(userInput));
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
